import { useState, useRef, useEffect } from "react";
import { useLang } from "../../context/LangContext";
import "./ClassifyPage.css";

const API_URL = process.env.REACT_APP_AI_URL;

const PRESET_CROPS = [
  { label: "1:1", ratio: 1 },
  { label: "4:3", ratio: 4 / 3 },
  { label: "16:9", ratio: 16 / 9 },
];

export default function ClassifyPage() {
  const { lang } = useLang();

  // ================= STATE =================
  const [step, setStep] = useState("upload");
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [naturalSize, setNaturalSize] = useState(null);

  const [crop, setCrop] = useState(null);
  const [dragging, setDragging] = useState(false);
  const [mode, setMode] = useState("draw");

  const [adj, setAdj] = useState({
    brightness: 1,
    contrast: 1,
    color: 1,
  });

  const [history, setHistory] = useState([]);
  const [redoStack, setRedoStack] = useState([]);

  const [result, setResult] = useState(null);
  const [error, setError] = useState("");

  const cropAreaRef = useRef(null);
  const startRef = useRef(null);
  const fileInputRef = useRef(null);

  // ================= FILTER =================
  const imgFilter = `
    brightness(${adj.brightness})
    contrast(${adj.contrast})
    saturate(${adj.color})
  `;

  // ================= FILE =================
  const handleFile = (f) => {
    if (!f) return;

    setFile(f);
    setError("");
    setResult(null);
    setCrop(null);
    setHistory([]);
    setRedoStack([]);

    const url = URL.createObjectURL(f);
    setPreview(url);

    const img = new Image();
    img.onload = () =>
      setNaturalSize({ w: img.naturalWidth, h: img.naturalHeight });
    img.src = url;

    setStep("edit");
  };

  const handleDrop = (e) => {
    e.preventDefault();
    handleFile(e.dataTransfer.files?.[0]);
  };

  // ================= POSITION =================
  const getPos = (e, el) => {
    const rect = el.getBoundingClientRect();
    const touch = e.touches?.[0] ?? e;

    return {
      x: Math.max(0, Math.min(touch.clientX - rect.left, rect.width)),
      y: Math.max(0, Math.min(touch.clientY - rect.top, rect.height)),
    };
  };

  // ================= CROP LOGIC =================
  const onStart = (e) => {
    if (!cropAreaRef.current) return;

    const pos = getPos(e, cropAreaRef.current);

    if (
      crop &&
      pos.x > crop.x &&
      pos.x < crop.x2 &&
      pos.y > crop.y &&
      pos.y < crop.y2
    ) {
      setMode("move");
      startRef.current = { pos, crop };
    } else {
      setMode("draw");
      startRef.current = pos;
      setCrop({ x: pos.x, y: pos.y, x2: pos.x, y2: pos.y });
    }

    setDragging(true);
  };

  const onMove = (e) => {
    if (!dragging || !startRef.current || !cropAreaRef.current) return;

    const pos = getPos(e, cropAreaRef.current);

    if (mode === "draw") {
      setCrop({
        x: Math.min(startRef.current.x, pos.x),
        y: Math.min(startRef.current.y, pos.y),
        x2: Math.max(startRef.current.x, pos.x),
        y2: Math.max(startRef.current.y, pos.y),
      });
    }

    if (mode === "move") {
      const dx = pos.x - startRef.current.pos.x;
      const dy = pos.y - startRef.current.pos.y;
      const c = startRef.current.crop;

      setCrop({
        x: c.x + dx,
        y: c.y + dy,
        x2: c.x2 + dx,
        y2: c.y2 + dy,
      });
    }
  };

  const onEnd = () => setDragging(false);

  // ================= PRESET =================
  const applyPreset = (preset) => {
    const rect = cropAreaRef.current.getBoundingClientRect();

    let w = rect.width * 0.6;
    let h = rect.height * 0.6;

    if (preset.ratio) {
      if (w / h > preset.ratio) w = h * preset.ratio;
      else h = w / preset.ratio;
    }

    const x = (rect.width - w) / 2;
    const y = (rect.height - h) / 2;

    setCrop({ x, y, x2: x + w, y2: y + h });
  };

  // ================= HISTORY =================
  useEffect(() => {
    if (crop) {
      setHistory((h) => [...h, crop]);
      setRedoStack([]);
    }
  }, [crop]);

  const undo = () => {
    setHistory((h) => {
      if (h.length < 2) return h;
      const newH = [...h];
      const last = newH.pop();
      setRedoStack((r) => [...r, last]);
      setCrop(newH[newH.length - 1]);
      return newH;
    });
  };

  const redo = () => {
    setRedoStack((r) => {
      if (!r.length) return r;
      const last = r[r.length - 1];
      setHistory((h) => [...h, last]);
      setCrop(last);
      return r.slice(0, -1);
    });
  };

  // ================= CROP REAL =================
  const toImageCoords = (elW, elH) => {
    if (!crop || !naturalSize) return null;

    const scaleX = naturalSize.w / elW;
    const scaleY = naturalSize.h / elH;

    return {
      x: crop.x * scaleX,
      y: crop.y * scaleY,
      w: (crop.x2 - crop.x) * scaleX,
      h: (crop.y2 - crop.y) * scaleY,
    };
  };

  const applyCropImage = () => {
    if (!crop) return;

    const img = new Image();
    img.src = preview;

    img.onload = () => {
      const el = cropAreaRef.current;
      const coords = toImageCoords(el.clientWidth, el.clientHeight);

      const canvas = document.createElement("canvas");
      const ctx = canvas.getContext("2d");

      canvas.width = coords.w;
      canvas.height = coords.h;

      ctx.drawImage(
        img,
        coords.x,
        coords.y,
        coords.w,
        coords.h,
        0,
        0,
        coords.w,
        coords.h
      );

      canvas.toBlob((blob) => {
        const newFile = new File([blob], "crop.jpg", { type: "image/jpeg" });
        handleFile(newFile);
      });
    };
  };

  // ================= ANALYZE =================
  const handleAnalyze = async () => {
    if (!file) return;

    setStep("loading");

    const form = new FormData();
    form.append("file", file);

    try {
      const res = await fetch(`${API_URL}/api/ai/classify`, {
        method: "POST",
        body: form,
      });

      const data = await res.json();
      setResult(data);
      setStep("result");
    } catch {
      setError("Server error");
      setStep("edit");
    }
  };

  // ================= UI =================
  return (
    <div className="cls-wrapper">

      {/* UPLOAD */}
      {step === "upload" && (
        <div className="cls-dropzone"
          onDrop={handleDrop}
          onDragOver={(e) => e.preventDefault()}
          onClick={() => fileInputRef.current.click()}
        >
          <p>Drop or Click</p>
          <input
            ref={fileInputRef}
            type="file"
            hidden
            onChange={(e) => handleFile(e.target.files[0])}
          />
        </div>
      )}

      {/* EDIT */}
      {step === "edit" && preview && (
        <div className="cls-edit-layout">

          {/* IMAGE */}
          <div
            ref={cropAreaRef}
            className="crop-area"
            onMouseDown={onStart}
            onMouseMove={onMove}
            onMouseUp={onEnd}
          >
            <img src={preview} style={{ filter: imgFilter }} />

            {crop && (
              <div
                className="crop-box"
                style={{
                  left: crop.x,
                  top: crop.y,
                  width: crop.x2 - crop.x,
                  height: crop.y2 - crop.y,
                }}
              />
            )}
          </div>

          {/* CONTROL */}
          <div>

            {/* PRESET */}
            <div>
              {PRESET_CROPS.map((p) => (
                <button key={p.label} onClick={() => applyPreset(p)}>
                  {p.label}
                </button>
              ))}
            </div>

            {/* ACTION */}
            <button onClick={applyCropImage}>Crop</button>
            <button onClick={undo}>Undo</button>
            <button onClick={redo}>Redo</button>

            {/* ANALYZE */}
            <button onClick={handleAnalyze}>
              Analyze
            </button>

          </div>
        </div>
      )}

      {/* RESULT */}
      {step === "result" && result && (
        <div>
          <h2>{result.top?.label}</h2>
          <button onClick={() => setStep("edit")}>Back</button>
        </div>
      )}

    </div>
  );
}
